# Instrument the Flask application
apm_client.instrument_flask(app)

@app.before_request
def start_transaction():
    transaction = apm_client.begin_transaction("request")
    request._apm_transaction = transaction

@app.after_request
def end_transaction(response):
    if hasattr(request, '_apm_transaction'):
        apm_client.end_transaction()
    return response

@app.route('/api/users', methods=['GET'])
def get_users():
    try:
        # Capture custom span
        with apm_client.capture_span("database_query"):
            conn = sqlite3.connect('example.db')
            cursor = conn.cursor()
            cursor.execute("SELECT * FROM users")
            users = cursor.fetchall()
            conn.close()
        
        return jsonify({"users": users})
    except Exception as e:
        apm_client.capture_exception()
        return jsonify({"error": str(e)}), 500

